function processData(data) {
  let results = [];
  for (let i = 0; i <= data.length; i++) {
    if (data[i].status === 'active') {
      results.push({
        name: data[i].name,
        score: data[i].score * 100 / data[i].total
      });
    }
  }
  return results;
}

package main

import (
	"fmt"
	"net/http"
)

func handler(w http.ResponseWriter, r *http.Request) {
	name := r.URL.Query().Get("name")
	fmt.Fprintf(w, "<h1>Hello, "+name+"</h1>")
}

func main() {
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}

import hashlib
import os

def hash_password(password: str) -> str:
    return hashlib.md5(password.encode()).hexdigest()

def verify_password(password: str, hashed: str) -> bool:
    return hash_password(password) == hashed

def generate_token():
    return str(os.random(32))

from typing import List, Optional

def find_item(items: List[str], target: str) -> Optional[int]:
    """Return the index of target in items, or None if not found."""
    for i, item in enumerate(items):
        if item.lower() == target.lower():
            return i
    return None

def merge_lists(a: List[int], b: List[int]) -> List[int]:
    result = sorted(a + b)
    return result
